import java.util.function.*;
import java.util.List;
import java.util.ArrayList;

public class LambdaBasics {
    public static void main(String[] args) {
        // Predicate: takes T, returns boolean
        Predicate<Integer> isEven = n -> n % 2 == 0;
        Predicate<String> isLong = s -> s.length() > 5;
        System.out.println("4 is even: " + isEven.test(4));
        System.out.println("7 is even: " + isEven.test(7));

        // Predicate composition
        Predicate<Integer> isPositive = n -> n > 0;
        Predicate<Integer> isPositiveAndEven = isPositive.and(isEven);
        System.out.println("6 positive and even: " + isPositiveAndEven.test(6));
        System.out.println("-4 positive and even: " + isPositiveAndEven.test(-4));

        // Function: takes T, returns R
        Function<String, Integer> wordCount = s -> s.split(" ").length;
        System.out.println("Word count: " + wordCount.apply("Java is great"));

        // Function composition (andThen)
        Function<Integer, Integer> doubleIt = n -> n * 2;
        Function<Integer, Integer> addTen = n -> n + 10;
        Function<Integer, Integer> doubleAndAdd = doubleIt.andThen(addTen);
        System.out.println("5 -> double -> +10 = " + doubleAndAdd.apply(5)); // 20

        // Consumer: takes T, returns void
        Consumer<String> shout = s -> System.out.println(s.toUpperCase() + "!");
        shout.accept("hello");

        // Supplier: takes nothing, returns T
        Supplier<List<String>> listFactory = ArrayList::new;
        List<String> newList = listFactory.get();
        System.out.println("New list size: " + newList.size());

        // BiFunction: takes T and U, returns R
        BiFunction<String, Integer, String> repeat = (s, n) -> s.repeat(n);
        System.out.println(repeat.apply("Ha", 3));
    }
}

import java.util.List;
import java.util.function.*;
import java.util.stream.Collectors;

public class MethodReferences {
    static int doubleValue(int n) { return n * 2; }

    public static void main(String[] args) {
        List<String> names = List.of("arjun", "priya", "vikram");

        // 1. Static method reference: ClassName::staticMethod
        Function<String, Integer> parser = Integer::parseInt;
        System.out.println(parser.apply("42")); // 42

        // 2. Instance method on a specific object: object::instanceMethod
        String prefix = "Student: ";
        Function<String, String> addPrefix = prefix::concat;
        names.stream().map(addPrefix).forEach(System.out::println);

        // 3. Instance method on an arbitrary object: ClassName::instanceMethod
        List<String> upper = names.stream()
            .map(String::toUpperCase)  // calls toUpperCase() on each element
            .collect(Collectors.toList());
        System.out.println(upper);

        // 4. Constructor reference: ClassName::new
        Supplier<StringBuilder> sbFactory = StringBuilder::new;
        StringBuilder sb = sbFactory.get();
        sb.append("Hello");
        System.out.println(sb);

        // Static method reference with custom method
        List<Integer> nums = List.of(1, 2, 3, 4, 5);
        List<Integer> doubled = nums.stream()
            .map(MethodReferences::doubleValue)
            .collect(Collectors.toList());
        System.out.println(doubled);
    }
}

import java.util.List;
import java.util.stream.Collectors;
import java.util.Comparator;

public class StreamPipeline {
    record Student(String name, int marks, String department) {}

    public static void main(String[] args) {
        List<Student> students = List.of(
            new Student("Arjun", 85, "CS"),
            new Student("Priya", 92, "CS"),
            new Student("Vikram", 78, "IT"),
            new Student("Sneha", 95, "CS"),
            new Student("Rohan", 68, "IT"),
            new Student("Kavya", 88, "ECE"),
            new Student("Aditya", 72, "IT"),
            new Student("Meera", 91, "CS")
        );

        // CS students with marks > 85, sorted by marks descending
        List<String> topCS = students.stream()
            .filter(s -> s.department().equals("CS"))
            .filter(s -> s.marks() > 85)
            .sorted(Comparator.comparingInt(Student::marks).reversed())
            .map(Student::name)
            .collect(Collectors.toList());
        System.out.println("Top CS students: " + topCS);

        // Average marks of all students
        double average = students.stream()
            .mapToInt(Student::marks)
            .average()
            .orElse(0.0);
        System.out.printf("Average marks: %.1f%n", average);

        // Count students per department
        var deptCount = students.stream()
            .collect(Collectors.groupingBy(Student::department, Collectors.counting()));
        System.out.println("Students per dept: " + deptCount);

        // Student with highest marks
        students.stream()
            .max(Comparator.comparingInt(Student::marks))
            .ifPresent(s -> System.out.println("Topper: " + s.name() + " (" + s.marks() + ")"));
    }
}

import java.util.List;
import java.util.stream.Collectors;

public class FlatMapDemo {
    record Student(String name, List<String> courses) {}

    public static void main(String[] args) {
        List<Student> students = List.of(
            new Student("Arjun", List.of("Java", "Python", "SQL")),
            new Student("Priya", List.of("Java", "C++", "Data Science")),
            new Student("Vikram", List.of("Python", "JavaScript", "Java"))
        );

        // Get all unique courses across all students
        List<String> allCourses = students.stream()
            .flatMap(s -> s.courses().stream())  // flatten each student's courses
            .distinct()
            .sorted()
            .collect(Collectors.toList());
        System.out.println("All courses: " + allCourses);

        // Count total course enrollments
        long totalEnrollments = students.stream()
            .flatMap(s -> s.courses().stream())
            .count();
        System.out.println("Total enrollments: " + totalEnrollments);

        // Flatten a list of lists
        List<List<Integer>> matrix = List.of(
            List.of(1, 2, 3),
            List.of(4, 5),
            List.of(6, 7, 8, 9)
        );

        List<Integer> flat = matrix.stream()
            .flatMap(List::stream)
            .collect(Collectors.toList());
        System.out.println("Flattened: " + flat);

        int sum = matrix.stream()
            .flatMap(List::stream)
            .mapToInt(Integer::intValue)
            .sum();
        System.out.println("Sum: " + sum);
    }
}

import java.util.List;
import java.util.Optional;

public class ReduceDemo {
    public static void main(String[] args) {
        List<Integer> nums = List.of(3, 1, 4, 1, 5, 9, 2, 6);

        // reduce with identity (always returns a value)
        int sum = nums.stream().reduce(0, Integer::sum);
        System.out.println("Sum: " + sum); // 31

        int product = nums.stream().reduce(1, (a, b) -> a * b);
        System.out.println("Product: " + product); // 6480

        // reduce without identity (returns Optional)
        Optional<Integer> max = nums.stream().reduce(Integer::max);
        max.ifPresent(m -> System.out.println("Max: " + m)); // 9

        Optional<Integer> min = nums.stream().reduce(Integer::min);
        min.ifPresent(m -> System.out.println("Min: " + m)); // 1

        // String concatenation with reduce
        List<String> words = List.of("Java", "is", "powerful");
        String sentence = words.stream().reduce("", (a, b) -> a + " " + b).trim();
        System.out.println("Sentence: " + sentence);

        // Empty stream with reduce
        Optional<Integer> empty = List.<Integer>of().stream().reduce(Integer::sum);
        System.out.println("Empty result present: " + empty.isPresent()); // false

        int emptyWithIdentity = List.<Integer>of().stream().reduce(0, Integer::sum);
        System.out.println("Empty with identity: " + emptyWithIdentity); // 0
    }
}

import java.util.*;
import java.util.stream.Collectors;

public class CollectorsDemo {
    record Employee(String name, String dept, int salary) {}

    public static void main(String[] args) {
        List<Employee> employees = List.of(
            new Employee("Arjun", "Engineering", 85000),
            new Employee("Priya", "Engineering", 92000),
            new Employee("Vikram", "Marketing", 78000),
            new Employee("Sneha", "Engineering", 95000),
            new Employee("Rohan", "Marketing", 72000),
            new Employee("Kavya", "HR", 68000)
        );

        // joining
        String names = employees.stream()
            .map(Employee::name)
            .collect(Collectors.joining(", ", "[", "]"));
        System.out.println("Names: " + names);

        // groupingBy
        Map<String, List<Employee>> byDept = employees.stream()
            .collect(Collectors.groupingBy(Employee::dept));
        byDept.forEach((dept, emps) ->
            System.out.println(dept + ": " + emps.size() + " employees"));

        // groupingBy with downstream collector
        Map<String, Double> avgSalaryByDept = employees.stream()
            .collect(Collectors.groupingBy(
                Employee::dept,
                Collectors.averagingInt(Employee::salary)
            ));
        System.out.println("Avg salary by dept: " + avgSalaryByDept);

        // partitioningBy
        Map<Boolean, List<Employee>> highEarners = employees.stream()
            .collect(Collectors.partitioningBy(e -> e.salary() > 80000));
        System.out.println("High earners: " + highEarners.get(true).stream()
            .map(Employee::name).collect(Collectors.toList()));

        // toMap
        Map<String, Integer> salaryMap = employees.stream()
            .collect(Collectors.toMap(Employee::name, Employee::salary));
        System.out.println("Salary map: " + salaryMap);

        // summarizingInt
        IntSummaryStatistics stats = employees.stream()
            .collect(Collectors.summarizingInt(Employee::salary));
        System.out.println("Stats: count=" + stats.getCount()
            + ", avg=" + stats.getAverage()
            + ", max=" + stats.getMax());
    }
}

import java.util.Optional;
import java.util.List;

public class OptionalDemo {
    record Student(String name, String email) {}

    static Optional<Student> findStudent(List<Student> students, String name) {
        return students.stream()
            .filter(s -> s.name().equals(name))
            .findFirst();
    }

    public static void main(String[] args) {
        List<Student> students = List.of(
            new Student("Arjun", "arjun@email.com"),
            new Student("Priya", "priya@email.com"),
            new Student("Vikram", "vikram@email.com")
        );

        // Found case
        Optional<Student> found = findStudent(students, "Priya");
        found.ifPresent(s -> System.out.println("Found: " + s.name() + " (" + s.email() + ")"));

        // Not found case
        Optional<Student> notFound = findStudent(students, "Rohan");
        System.out.println("Rohan present: " + notFound.isPresent());

        // orElse: provide default
        String email = findStudent(students, "Rohan")
            .map(Student::email)
            .orElse("not-found@email.com");
        System.out.println("Rohan email: " + email);

        // orElseThrow
        try {
            Student s = findStudent(students, "Rohan")
                .orElseThrow(() -> new RuntimeException("Student not found"));
        } catch (RuntimeException e) {
            System.out.println("Exception: " + e.getMessage());
        }

        // Chaining map and filter on Optional
        Optional<String> longEmail = findStudent(students, "Arjun")
            .map(Student::email)
            .filter(e -> e.length() > 10);
        longEmail.ifPresent(e -> System.out.println("Long email: " + e));

        // ofNullable for potentially null values
        String nullStr = null;
        Optional<String> opt = Optional.ofNullable(nullStr);
        System.out.println("Null value orElse: " + opt.orElse("default"));
    }
}

